const payload = $json.body ?? $json;
const request = payload.request ?? payload;
const text = String(request.text ?? '').trim();
const channel = String(request.channel ?? 'UNKNOWN').trim().toUpperCase();
const inventoryChoices = Array.isArray(request.inventoryChoices)
  ? request.inventoryChoices
      .filter((choice) => choice && typeof choice.id === 'string' && typeof choice.name === 'string')
      .slice(0, 120)
      .map((choice) => ({
        id: String(choice.id),
        name: String(choice.name),
        sku: typeof choice.sku === 'string' ? choice.sku : null,
      }))
  : [];
const rawLlm = payload.llm && typeof payload.llm === 'object' ? payload.llm : {};
const llmProvider = rawLlm.provider === 'cloudflare' ? 'cloudflare' : 'ollama';
const llm = {
  provider: llmProvider,
  url: typeof rawLlm.url === 'string' && rawLlm.url.trim() ? rawLlm.url.trim() : 'http://127.0.0.1:11434/api/chat',
  model: typeof rawLlm.model === 'string' && rawLlm.model.trim() ? rawLlm.model.trim() : 'qwen2.5:3b',
  headers: rawLlm.headers && typeof rawLlm.headers === 'object' ? rawLlm.headers : { 'Content-Type': 'application/json' },
};
const conversationHistory = Array.isArray(request.conversationHistory)
  ? request.conversationHistory
      .filter((t) => t && typeof t.role === 'string' && typeof t.text === 'string')
      .slice(-10)
      .map((t) => ({ role: String(t.role), text: String(t.text).slice(0, 500) }))
  : [];
const rawPending = request.pendingContext && typeof request.pendingContext === 'object' && !Array.isArray(request.pendingContext) ? request.pendingContext : null;
const pendingContext = rawPending ? {
  intent: typeof rawPending.intent === 'string' ? rawPending.intent : 'UNKNOWN',
  inventoryItemId: typeof rawPending.inventoryItemId === 'string' ? rawPending.inventoryItemId : null,
  inventoryItemName: typeof rawPending.inventoryItemName === 'string' ? rawPending.inventoryItemName : null,
  reportedOnHand: typeof rawPending.reportedOnHand === 'number' ? rawPending.reportedOnHand : null,
  clarificationQuestion: typeof rawPending.clarificationQuestion === 'string' ? rawPending.clarificationQuestion : '',
} : null;
if (!text) {
  throw new Error('Missing bot text.');
}
if (!inventoryChoices.length) {
  throw new Error('Missing inventory choices.');
}
return [{ json: { event: payload.event ?? null, occurredAt: payload.occurredAt ?? null, channel, text, inventoryChoices, conversationHistory, pendingContext, llm, receivedAt: new Date().toISOString() } }];

const inventoryList = $json.inventoryChoices
  .map((choice) => `- ${choice.id}: ${choice.name}${choice.sku ? ` (SKU: ${choice.sku})` : ''}`)
  .join('\n');
const responseSchema = {
  type: 'object',
  properties: {
    intent: {
      type: 'string',
      enum: ['RESTOCK_TO_PAR', 'STOCK_STATUS', 'GREETING', 'HELP', 'UNKNOWN'],
    },
    inventoryItemId: {
      type: ['string', 'null'],
    },
    inventoryItemName: {
      type: ['string', 'null'],
    },
    reportedOnHand: {
      type: ['integer', 'null'],
      minimum: 0,
    },
    needsClarification: {
      type: 'boolean',
    },
    clarificationQuestion: {
      type: ['string', 'null'],
    },
    confidence: {
      type: 'number',
      minimum: 0,
      maximum: 1,
    },
    summary: {
      type: ['string', 'null'],
    },
  },
  required: [
    'intent',
    'inventoryItemId',
    'inventoryItemName',
    'reportedOnHand',
    'needsClarification',
    'clarificationQuestion',
    'confidence',
    'summary',
  ],
  additionalProperties: false,
};
const system = [
  'You interpret manager chat messages for StockPilot, an inventory operating system for cafes and small restaurants.',
  'Return JSON only and never wrap it in markdown.',
  'Use only the inventory ids from the provided inventory list.',
  'Supported intents are RESTOCK_TO_PAR, STOCK_STATUS, GREETING, HELP, UNKNOWN.',
  'RESTOCK_TO_PAR means the manager wants you to reorder or top up an item because it is low or running out.',
  'STOCK_STATUS means the manager is asking what is left, how much there is, or what is low overall.',
  'If the message includes phrases like order more, reorder, restock, top up, or we are running out, prefer RESTOCK_TO_PAR over STOCK_STATUS.',
  'Use GREETING for casual social messages like hi, hello, yo, sup, how are you, how r u, or thanks, unless the same message clearly asks about inventory.',
  'HELP is for what the bot can do or how to use it.',
  'UNKNOWN is for everything else.',
  'If a reorder request is missing the count or item, set needsClarification true and ask a short operational clarification question.',
  'If a stock question clearly names one item, include that inventoryItemId. If it is a general question, leave inventoryItemId null.',
  'Do not invent numbers. Only use a reportedOnHand value if the manager explicitly gave one.',
  'If a pending clarification context is provided, the manager is answering a previous question. Use it along with the current message to complete the interpretation — do not ask for clarification again if you can resolve it.',
  'If conversation history is provided, use it to understand follow-up messages. A short reply like "cherry" or "3" makes sense only in context of the previous exchange.',
].join(' ');
const examples = [
  'Example 1: "Whole milk 2 left, order more." -> RESTOCK_TO_PAR for Whole Milk with reportedOnHand 2.',
  'Example 2: "How much oat milk do we have?" -> STOCK_STATUS for Oat Milk.',
  'Example 3: "What are we low on right now?" -> STOCK_STATUS with no specific inventoryItemId.',
  'Example 4: "hi" -> GREETING.',
  'Example 5: "yo" -> GREETING.',
  'Example 6: "how are u" -> GREETING.',
  'Example 7 (with history): Bot asked "Which tomatoes — cherry or roma?", manager replies "cherry" -> RESTOCK_TO_PAR for Cherry Tomatoes using the count from the pending context.',
  'Example 8 (with history): Bot asked "How many do you have left?", manager replies "3" -> RESTOCK_TO_PAR for the item from pending context with reportedOnHand 3.',
].join('\n');
let historySection = '';
if ($json.conversationHistory && $json.conversationHistory.length > 0) {
  const lines = $json.conversationHistory
    .map((t) => `[${t.role === 'manager' ? 'Manager' : 'StockPilot'}]: ${t.text}`)
    .join('\n');
  historySection = `\nConversation history (oldest first):\n${lines}\n`;
}
let pendingSection = '';
if ($json.pendingContext) {
  const p = $json.pendingContext;
  pendingSection = `\nPending clarification: StockPilot previously asked: "${p.clarificationQuestion}"`;
  if (p.inventoryItemName) pendingSection += ` about item "${p.inventoryItemName}" (id: ${p.inventoryItemId})`;
  if (p.reportedOnHand !== null && p.reportedOnHand !== undefined) pendingSection += ` with reported count ${p.reportedOnHand}`;
  pendingSection += '. The current manager message is likely answering that question.\n';
}
const user = `Channel: ${$json.channel}${historySection}${pendingSection}\nCurrent manager message: ${$json.text}\n\nAvailable inventory choices:\n${inventoryList}\n\nExamples:\n${examples}\n\nReturn JSON with exactly these keys:\nintent, inventoryItemId, inventoryItemName, reportedOnHand, needsClarification, clarificationQuestion, confidence, summary`;
const messages = [
  { role: 'system', content: system },
  { role: 'user', content: `${user}\n\nReturn valid JSON only.` },
];
const llmRequest = $json.llm.provider === 'cloudflare'
  ? {
      model: $json.llm.model,
      messages,
      temperature: 0.15,
      max_tokens: 300,
      response_format: {
        type: 'json_schema',
        json_schema: responseSchema,
      },
    }
  : {
      model: $json.llm.model,
      stream: false,
      format: 'json',
      options: {
        temperature: 0.15,
      },
      messages,
    };
return [{ json: { llm: $json.llm, llmRequest } }];

function extractRawText(payload) {
  const openAiContent = payload?.choices?.[0]?.message?.content;
  if (typeof openAiContent === 'string' && openAiContent.trim()) {
    return openAiContent.trim();
  }
  if (Array.isArray(openAiContent)) {
    const textPart = openAiContent.find(
      (part) => part && part.type === 'text' && typeof part.text === 'string' && part.text.trim()
    );
    if (textPart?.text) {
      return textPart.text.trim();
    }
  }
  if (openAiContent && typeof openAiContent === 'object') {
    return JSON.stringify(openAiContent);
  }
  const ollamaContent = typeof payload?.message?.content === 'string' ? payload.message.content.trim() : '';
  return ollamaContent;
}

const rawText = extractRawText($json);
if (!rawText) {
  throw new Error('The LLM did not return usable message content.');
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`The LLM returned invalid JSON: ${rawText}`);
}

const confidence = Number(parsed.confidence);
const provider = Array.isArray($json.choices) ? 'n8n-cloudflare' : 'n8n-ollama';

return [{
  json: {
    accepted: true,
    provider,
    interpretation: {
      intent: typeof parsed.intent === 'string' ? parsed.intent.toUpperCase() : 'UNKNOWN',
      inventoryItemId: typeof parsed.inventoryItemId === 'string' ? parsed.inventoryItemId : null,
      inventoryItemName: typeof parsed.inventoryItemName === 'string' ? parsed.inventoryItemName : null,
      reportedOnHand: Number.isFinite(Number(parsed.reportedOnHand)) ? Math.max(0, Math.round(Number(parsed.reportedOnHand))) : null,
      needsClarification: parsed.needsClarification === true,
      clarificationQuestion: typeof parsed.clarificationQuestion === 'string' ? parsed.clarificationQuestion : null,
      confidence: Number.isFinite(confidence) ? Math.min(0.99, Math.max(0.05, confidence)) : 0.55,
      summary: typeof parsed.summary === 'string' ? parsed.summary : null,
      rawLlmText: rawText,
    },
  },
}];
